import React, { Component } from 'react';

class NavBar extends Component {
    render() { 
        return (
            <div>
                <nav className="navbar navbar-expand-lg navbar-light bg-light shadow-sm">
                    <div className="container-fluid px-4">

                        {/* Left - Logo */}
                        <a className="navbar-brand fw-bold" href="#home">
                        <i className="bi bi-heart-fill text-danger me-2"></i>
                        MyApp
                        </a>

                        {/* Center - Links */}
                        <div className="collapse navbar-collapse justify-content-center" id="navbarNav">
                        <ul className="navbar-nav">
                            <li className="nav-item mx-3"><a className="nav-link" href="#profile">Profile</a></li>
                            <li className="nav-item mx-3"><a className="nav-link" href="#donation">Donation</a></li>
                            <li className="nav-item mx-3"><a className="nav-link" href="#collection">Collection</a></li>
                            <li className="nav-item mx-3"><a className="nav-link" href="#feature">Feature</a></li>
                            <li className="nav-item mx-3"><a className="nav-link" href="#authority">Authority</a></li>
                        </ul>
                        </div>

                        {/* Right - Logout */}
                        <div className="d-flex">
                        <button className="btn btn-primary">
                            <i className="bi bi-box-arrow-right me-1"></i>
                            Logout
                        </button>
                        </div>
                    </div>
                </nav>
            </div>

        );
    }
}

export default NavBar;
